INSERT INTO public.posts (title, slug, content, excerpt, category, published_at, is_published, cover_image_url) VALUES
('Semana de la Epilepsia', 'semana-epilepsia', '		<div data-elementor-type="wp-post" data-elementor-id="1125" class="elementor elementor-1125" data-elementor-post-type="post">\n						<section class="elementor-section elementor-top-section elementor-element elementor-element-5eb10f7 elementor-section-boxed elementor-section-height-default elementor-section-height-default" data-id="5eb10f7" data-element_type="section" data-settings="{&quot;background_background&quot;:&quot;classic&quot;}">\n						<div class="elementor-container elementor-column-gap-default">\n					<div class="elementor-column elementor-col-100 elementor-top-column elementor-element elementor-element-957eee9" data-id="957eee9" data-element_type="column">\n			<div class="elementor-widget-wrap elementor-element-populated">\n						<div class="elementor-element elementor-element-6e1df34 elementor-widget elementor-widget-theme-post-title elementor-page-title elementor-widget-heading" data-id="6e1df34" data-element_type="widget" data-widget_type="theme-post-title.default">\n				<div class="elementor-widget-container">\n					<h1 class="elementor-heading-title elementor-size-default">Semana de la Epilepsia</h1>				</div>\n				</div>\n					</div>\n		</div>\n					</div>\n		</section>\n				<section class="elementor-section elementor-top-section elementor-element elementor-element-07bc4b7 elementor-section-boxed elementor-section-height-default elementor-section-height-default" data-id="07bc4b7" data-element_type="section">\n						<div class="elementor-container elementor-column-gap-default">\n					<div class="elementor-column elementor-col-100 elementor-top-column elementor-element elementor-element-0a591f2" data-id="0a591f2" data-element_type="column">\n			<div class="elementor-widget-wrap elementor-element-populated">\n						<div class="elementor-element elementor-element-c15914b elementor-widget elementor-widget-heading" data-id="c15914b" data-element_type="widget" data-widget_type="heading.default">\n				<div class="elementor-widget-container">\n					<h2 class="elementor-heading-title elementor-size-default">El simposio de\nTecnología y epilepsia</h2>				</div>\n				</div>\n				<div class="elementor-element elementor-element-035d772 elementor-widget elementor-widget-text-editor" data-id="035d772" data-element_type="widget" data-widget_type="text-editor.default">\n				<div class="elementor-widget-container">\n									<p>¡Hola! Desde Espacio Epilepsia, nos alegra muchísimo anunciar que llega primer simposio de Tecnología y epilepsia Techsia!.</p><p><strong style="font-style: inherit; color: var( --e-global-color-text ); background-color: var(--ast-global-color-5);">25 de Agosto de 2023<br /></strong><span style="font-weight: bold;">PRESENCIAL Y GRATUITO <br /></span></p>								</div>\n				</div>\n				<div class="elementor-element elementor-element-018db24 elementor-widget elementor-widget-image" data-id="018db24" data-element_type="widget" data-widget_type="image.default">\n				<div class="elementor-widget-container">\n															<img fetchpriority="high" decoding="async" width="1024" height="1024" src="https://espacioepilepsia.org/wp-content/uploads/2023/07/1_eventos-1024x1024.jpeg" class="attachment-large size-large wp-image-1081" alt="" srcset="https://espacioepilepsia.org/wp-content/uploads/2023/07/1_eventos-1024x1024.jpeg 1024w, https://espacioepilepsia.org/wp-content/uploads/2023/07/1_eventos-300x300.jpeg 300w, https://espacioepilepsia.org/wp-content/uploads/2023/07/1_eventos-100x100.jpeg 100w, https://espacioepilepsia.org/wp-content/uploads/2023/07/1_eventos-600x600.jpeg 600w, https://espacioepilepsia.org/wp-content/uploads/2023/07/1_eventos-150x150.jpeg 150w, https://espacioepilepsia.org/wp-content/uploads/2023/07/1_eventos-768x768.jpeg 768w, https://espacioepilepsia.org/wp-content/uploads/2023/07/1_eventos.jpeg 1080w" sizes="(max-width: 1024px) 100vw, 1024px" />															</div>\n				</div>\n				<div class="elementor-element elementor-element-bc91465 elementor-widget elementor-widget-heading" data-id="bc91465" data-element_type="widget" data-widget_type="heading.default">\n				<div class="elementor-widget-container">\n					<h2 class="elementor-heading-title elementor-size-default">Sobre Techsia</h2>				</div>\n				</div>\n				<div class="elementor-element elementor-element-cfae861 elementor-widget elementor-widget-text-editor" data-id="cfae861" data-element_type="widget" data-widget_type="text-editor.default">\n				<div class="elementor-widget-container">\n									<p>Techsia es un evento que tiene la finalidad de difundir tecnologías vinculadas a la epilepsia en la comunidad, propone espacios de conversación entre los distintos sectores involucrados en la comunidad de la epilepsia.</p>								</div>\n				</div>\n				<div class="elementor-element elementor-element-c4f16df elementor-widget elementor-widget-video" data-id="c4f16df" data-element_type="widget" data-settings="{&quot;youtube_url&quot;:&quot;https:\/\/www.youtube.com\/watch?v=XHOmBV4js_E&quot;,&quot;video_type&quot;:&quot;youtube&quot;,&quot;controls&quot;:&quot;yes&quot;}" data-widget_type="video.default">\n				<div class="elementor-widget-container">\n							<div class="elementor-wrapper elementor-open-inline">\n			<div class="elementor-video"></div>		</div>\n						</div>\n				</div>\n				<div class="elementor-element elementor-element-4646b4b elementor-widget elementor-widget-heading" data-id="4646b4b" data-element_type="widget" data-widget_type="heading.default">\n				<div class="elementor-widget-container">\n					<h2 class="elementor-heading-title elementor-size-default">Experiencia de Techsia</h2>				</div>\n				</div>\n				<div class="elementor-element elementor-element-e63ed22 elementor-widget elementor-widget-text-editor" data-id="e63ed22" data-element_type="widget" data-widget_type="text-editor.default">\n				<div class="elementor-widget-container">\n									<ul><li>8 charlas</li><li>2 Side events, eventos de Innovación para pensar nuevas ideas de tecnología y epilepsia</li><li>Espacios de Vinculación</li><li>Hospital Anfitrión: FLENI</li><li>Las charlas serán grabadas y estarán disponibles en nuestras plataformas de Youtube.</li></ul>								</div>\n				</div>\n					</div>\n		</div>\n					</div>\n		</section>\n				<section class="elementor-section elementor-top-section elementor-element elementor-element-0a71802 elementor-section-boxed elementor-section-height-default elementor-section-height-default" data-id="0a71802" data-element_type="section" data-settings="{&quot;background_background&quot;:&quot;classic&quot;}">\n						<div class="elementor-container elementor-column-gap-default">\n					<div class="elementor-column elementor-col-100 elementor-top-column elementor-element elementor-element-cb06a7b" data-id="cb06a7b" data-element_type="column">\n			<div class="elementor-widget-wrap elementor-element-populated">\n						<div class="elementor-element elementor-element-df66228 elementor-widget elementor-widget-heading" data-id="df66228" data-element_type="widget" data-widget_type="heading.default">\n				<div class="elementor-widget-container">\n					<h2 class="elementor-heading-title elementor-size-default">¿Querés saber más?</h2>				</div>\n				</div>\n				<div class="elementor-element elementor-element-1974d5b elementor-align-center elementor-widget elementor-widget-button" data-id="1974d5b" data-element_type="widget" data-widget_type="button.default">\n				<div class="elementor-widget-container">\n									<div class="elementor-button-wrapper">\n					<a class="elementor-button elementor-button-link elementor-size-sm" href="https://docs.google.com/forms/d/1yXR5ic4Ogrl25LEhAZl3vPW_BIRSZdRnJcJLUmcSHaA/viewform?edit_requested=true">\n						<span class="elementor-button-content-wrapper">\n									<span class="elementor-button-text">¡Sumate!</span>\n					</span>\n					</a>\n				</div>\n								</div>\n				</div>\n					</div>\n		</div>\n					</div>\n		</section>\n				<section class="elementor-section elementor-top-section elementor-element elementor-element-5b5d929 elementor-section-boxed elementor-section-height-default elementor-section-height-default" data-id="5b5d929" data-element_type="section">\n						<div class="elementor-container elementor-column-gap-default">\n					<div class="elementor-column elementor-col-100 elementor-top-column elementor-element elementor-element-57503b9" data-id="57503b9" data-element_type="column">\n			<div class="elementor-widget-wrap elementor-element-populated">\n						<div class="elementor-element elementor-element-e5d1f6a elementor-widget elementor-widget-heading" data-id="e5d1f6a" data-element_type="widget" data-widget_type="heading.default">\n				<div class="elementor-widget-container">\n					<h2 class="elementor-heading-title elementor-size-default">Programa</h2>				</div>\n				</div>\n				<div class="elementor-element elementor-element-955d6f3 elementor-widget elementor-widget-text-editor" data-id="955d6f3" data-element_type="widget" data-widget_type="text-editor.default">\n				<div class="elementor-widget-container">\n									<ul><li>Tecnologías Predictivas, Tecnologías de Alerta y Tecnologías Paliativas</li><li>Presentaciones por profesionales de la salud de primera categoría, quienes compartirán las últimas novedades en neurología, terapias y tecnologías asistivas</li><li>Side events con innovadoras experiencias para fomentar el desarrollo de tecnologías en epilepsia</li></ul>								</div>\n				</div>\n				<div class="elementor-element elementor-element-a042598 elementor-align-center elementor-widget elementor-widget-button" data-id="a042598" data-element_type="widget" data-widget_type="button.default">\n				<div class="elementor-widget-container">\n									<div class="elementor-button-wrapper">\n					<a class="elementor-button elementor-button-link elementor-size-sm" href="https://docs.google.com/spreadsheets/d/1gYA-xijP7A0EusQKS8hoYKUpnq0msEdW4Ck7FTESNW0/edit#gid=414009378">\n						<span class="elementor-button-content-wrapper">\n									<span class="elementor-button-text">Ver cronograma</span>\n					</span>\n					</a>\n				</div>\n								</div>\n				</div>\n				<div class="elementor-element elementor-element-87aac25 elementor-widget elementor-widget-heading" data-id="87aac25" data-element_type="widget" data-widget_type="heading.default">\n				<div class="elementor-widget-container">\n					<h2 class="elementor-heading-title elementor-size-default">Charlas Propuestas</h2>				</div>\n				</div>\n				<div class="elementor-element elementor-element-aadbf1b elementor-widget elementor-widget-text-editor" data-id="aadbf1b" data-element_type="widget" data-widget_type="text-editor.default">\n				<div class="elementor-widget-container">\n									<ul><li>Cirugía con electrodos intracraneales en epilepsia Que es la SEEG Stereo Electro Encefalografia</li><li>“El Paso a paso de la colocación de electrodos en epilepsia” + Testimonio</li><li>“Nuevas técnicas quirúrgicas mínimamente invasivas &#8211; Realidad Argentina vs. Nivel Mundial” (LASER, Termolesión por radiofrecuencia, Robot para colocación de electrodos)</li><li>“Neuromodulación en epilepsia &#8211; Presente y Futuro + (Generalidades + VNS)” + testimonio de paciente (videos)</li><li>“DBS y RNS en epilepsia” “Tipos de dispositivos en epilepsia” &#8211; Clasificación y ejemplos</li><li>“Inteligencia Artificial y Diagnóstico en Epilepsia” Machine Learning en Epilepsia </li></ul>								</div>\n				</div>\n				<div class="elementor-element elementor-element-e4caddd elementor-widget elementor-widget-heading" data-id="e4caddd" data-element_type="widget" data-widget_type="heading.default">\n				<div class="elementor-widget-container">\n					<h2 class="elementor-heading-title elementor-size-default">¿A quiénes está destinado?</h2>				</div>\n				</div>\n				<div class="elementor-element elementor-element-737e349 elementor-widget elementor-widget-text-editor" data-id="737e349" data-element_type="widget" data-widget_type="text-editor.default">\n				<div class="elementor-widget-container">\n									<ul><li>Personas con epilepsia, familiares y amigos</li><li>Bioingenieros/as y estudiantes de bioingeniería</li><li>Profesionales de la salud</li><li>Emprendedores</li></ul>								</div>\n				</div>\n					</div>\n		</div>\n					</div>\n		</section>\n				<section class="elementor-section elementor-top-section elementor-element elementor-element-07409fa elementor-section-boxed elementor-section-height-default elementor-section-height-default" data-id="07409fa" data-element_type="section" data-settings="{&quot;background_background&quot;:&quot;classic&quot;}">\n						<div class="elementor-container elementor-column-gap-default">\n					<div class="elementor-column elementor-col-100 elementor-top-column elementor-element elementor-element-f1f31b0" data-id="f1f31b0" data-element_type="column">\n			<div class="elementor-widget-wrap elementor-element-populated">\n						<div class="elementor-element elementor-element-e251d42 elementor-widget elementor-widget-heading" data-id="e251d42" data-element_type="widget" data-widget_type="heading.default">\n				<div class="elementor-widget-container">\n					<h2 class="elementor-heading-title elementor-size-default">Inscribite al evento haciendo click acá</h2>				</div>\n				</div>\n				<div class="elementor-element elementor-element-4cda72b elementor-align-center elementor-widget elementor-widget-button" data-id="4cda72b" data-element_type="widget" data-widget_type="button.default">\n				<div class="elementor-widget-container">\n									<div class="elementor-button-wrapper">\n					<a class="elementor-button elementor-button-link elementor-size-sm" href="https://docs.google.com/forms/d/1yXR5ic4Ogrl25LEhAZl3vPW_BIRSZdRnJcJLUmcSHaA/viewform?edit_requested=true">\n						<span class="elementor-button-content-wrapper">\n									<span class="elementor-button-text">Ver más</span>\n					</span>\n					</a>\n				</div>\n								</div>\n				</div>\n					</div>\n		</div>\n					</div>\n		</section>\n				<section class="elementor-section elementor-top-section elementor-element elementor-element-d7c3e16 elementor-section-boxed elementor-section-height-default elementor-section-height-default" data-id="d7c3e16" data-element_type="section">\n						<div class="elementor-container elementor-column-gap-default">\n					<div class="elementor-column elementor-col-100 elementor-top-column elementor-element elementor-element-90db0e0" data-id="90db0e0" data-element_type="column">\n			<div class="elementor-widget-wrap elementor-element-populated">\n						<div class="elementor-element elementor-element-2344c6d elementor-widget elementor-widget-heading" data-id="2344c6d" data-element_type="widget" data-widget_type="heading.default">\n				<div class="elementor-widget-container">\n					<h2 class="elementor-heading-title elementor-size-default">¿Cómo apoyar esta iniciativa?</h2>				</div>\n				</div>\n				<div class="elementor-element elementor-element-70f1b8c elementor-widget elementor-widget-text-editor" data-id="70f1b8c" data-element_type="widget" data-widget_type="text-editor.default">\n				<div class="elementor-widget-container">\n									<p><strong>Ayudá a difundir el evento: </strong><br /><br />Auspiciante Sumate a la difusión de techsia para que más personas se puedan beneficiar. Te mandaremos material de difusión para que compartas por e-mail y/o en redes sociales. </p><p><strong>Apoyo:</strong> Este evento cuenta con el apoyo del Hospital FLENI y la Liga Argentina Contra la Epilepsia (LACE), miembro de la International League Againt Epilepsy (ILAE) contacto@espacioepilepsia.</p>								</div>\n				</div>\n					</div>\n		</div>\n					</div>\n		</section>\n				</div>\n		', 'El simposio de Tecnología y epilepsia ¡Hola! Desde Espacio Epilepsia, nos alegra muchísimo anunciar que llega primer simposio de Tecnología y epilepsia Techsia!. 25 de Agosto de 2023 PRESENCIAL Y GRATUITO&nbsp; Sobre Techsia Techsia es un evento que tiene la finalidad de difundir tecnologías vinculadas a la epilepsia en la comunidad, propone espacios de conversación [&hellip;]\n', 'blog', '2023-07-28T19:34:26', true, 'https://espacioepilepsia.org/wp-content/uploads/2023/05/icono-5.png'),
('Techsia23', 'techsia23', '		<div data-elementor-type="wp-post" data-elementor-id="1086" class="elementor elementor-1086" data-elementor-post-type="post">\n						<section class="elementor-section elementor-top-section elementor-element elementor-element-5eb10f7 elementor-section-boxed elementor-section-height-default elementor-section-height-default" data-id="5eb10f7" data-element_type="section" data-settings="{&quot;background_background&quot;:&quot;classic&quot;}">\n						<div class="elementor-container elementor-column-gap-default">\n					<div class="elementor-column elementor-col-100 elementor-top-column elementor-element elementor-element-957eee9" data-id="957eee9" data-element_type="column">\n			<div class="elementor-widget-wrap elementor-element-populated">\n						<div class="elementor-element elementor-element-6e1df34 elementor-widget elementor-widget-theme-post-title elementor-page-title elementor-widget-heading" data-id="6e1df34" data-element_type="widget" data-widget_type="theme-post-title.default">\n				<div class="elementor-widget-container">\n					<h1 class="elementor-heading-title elementor-size-default">Techsia23</h1>				</div>\n				</div>\n					</div>\n		</div>\n					</div>\n		</section>\n				<section class="elementor-section elementor-top-section elementor-element elementor-element-07bc4b7 elementor-section-boxed elementor-section-height-default elementor-section-height-default" data-id="07bc4b7" data-element_type="section">\n						<div class="elementor-container elementor-column-gap-default">\n					<div class="elementor-column elementor-col-100 elementor-top-column elementor-element elementor-element-0a591f2" data-id="0a591f2" data-element_type="column">\n			<div class="elementor-widget-wrap elementor-element-populated">\n						<div class="elementor-element elementor-element-c15914b elementor-widget elementor-widget-heading" data-id="c15914b" data-element_type="widget" data-widget_type="heading.default">\n				<div class="elementor-widget-container">\n					<h2 class="elementor-heading-title elementor-size-default">El simposio de\nTecnología y epilepsia</h2>				</div>\n				</div>\n				<div class="elementor-element elementor-element-035d772 elementor-widget elementor-widget-text-editor" data-id="035d772" data-element_type="widget" data-widget_type="text-editor.default">\n				<div class="elementor-widget-container">\n									<p>¡Hola! Desde Espacio Epilepsia, nos alegra muchísimo anunciar que llega primer simposio de Tecnología y epilepsia Techsia!.</p><p><strong style="font-style: inherit; color: var( --e-global-color-text ); background-color: var(--ast-global-color-5);">25 de Agosto de 2023<br /></strong><span style="font-weight: bold;">PRESENCIAL Y GRATUITO <br /></span></p>								</div>\n				</div>\n				<div class="elementor-element elementor-element-bc91465 elementor-widget elementor-widget-heading" data-id="bc91465" data-element_type="widget" data-widget_type="heading.default">\n				<div class="elementor-widget-container">\n					<h2 class="elementor-heading-title elementor-size-default">Sobre Techsia</h2>				</div>\n				</div>\n				<div class="elementor-element elementor-element-cfae861 elementor-widget elementor-widget-text-editor" data-id="cfae861" data-element_type="widget" data-widget_type="text-editor.default">\n				<div class="elementor-widget-container">\n									<p>Techsia es un evento que tiene la finalidad de difundir tecnologías vinculadas a la epilepsia en la comunidad, propone espacios de conversación entre los distintos sectores involucrados en la comunidad de la epilepsia.</p>								</div>\n				</div>\n				<div class="elementor-element elementor-element-4646b4b elementor-widget elementor-widget-heading" data-id="4646b4b" data-element_type="widget" data-widget_type="heading.default">\n				<div class="elementor-widget-container">\n					<h2 class="elementor-heading-title elementor-size-default">Experiencia de Techsia</h2>				</div>\n				</div>\n				<div class="elementor-element elementor-element-e63ed22 elementor-widget elementor-widget-text-editor" data-id="e63ed22" data-element_type="widget" data-widget_type="text-editor.default">\n				<div class="elementor-widget-container">\n									<ul><li>8 charlas</li><li>2 Side events, eventos de Innovación para pensar nuevas ideas de tecnología y epilepsia</li><li>Espacios de Vinculación</li><li>Hospital Anfitrión: FLENI</li><li>Las charlas serán grabadas y estarán disponibles en nuestras plataformas de Youtube.</li></ul>								</div>\n				</div>\n					</div>\n		</div>\n					</div>\n		</section>\n				<section class="elementor-section elementor-top-section elementor-element elementor-element-0a71802 elementor-section-boxed elementor-section-height-default elementor-section-height-default" data-id="0a71802" data-element_type="section" data-settings="{&quot;background_background&quot;:&quot;classic&quot;}">\n						<div class="elementor-container elementor-column-gap-default">\n					<div class="elementor-column elementor-col-100 elementor-top-column elementor-element elementor-element-cb06a7b" data-id="cb06a7b" data-element_type="column">\n			<div class="elementor-widget-wrap elementor-element-populated">\n						<div class="elementor-element elementor-element-df66228 elementor-widget elementor-widget-heading" data-id="df66228" data-element_type="widget" data-widget_type="heading.default">\n				<div class="elementor-widget-container">\n					<h2 class="elementor-heading-title elementor-size-default">¿Querés saber más?</h2>				</div>\n				</div>\n				<div class="elementor-element elementor-element-1974d5b elementor-align-center elementor-widget elementor-widget-button" data-id="1974d5b" data-element_type="widget" data-widget_type="button.default">\n				<div class="elementor-widget-container">\n									<div class="elementor-button-wrapper">\n					<a class="elementor-button elementor-button-link elementor-size-sm" href="https://docs.google.com/forms/d/1yXR5ic4Ogrl25LEhAZl3vPW_BIRSZdRnJcJLUmcSHaA/viewform?edit_requested=true">\n						<span class="elementor-button-content-wrapper">\n									<span class="elementor-button-text">¡Sumate!</span>\n					</span>\n					</a>\n				</div>\n								</div>\n				</div>\n					</div>\n		</div>\n					</div>\n		</section>\n				<section class="elementor-section elementor-top-section elementor-element elementor-element-5b5d929 elementor-section-boxed elementor-section-height-default elementor-section-height-default" data-id="5b5d929" data-element_type="section">\n						<div class="elementor-container elementor-column-gap-default">\n					<div class="elementor-column elementor-col-100 elementor-top-column elementor-element elementor-element-57503b9" data-id="57503b9" data-element_type="column">\n			<div class="elementor-widget-wrap elementor-element-populated">\n						<div class="elementor-element elementor-element-e5d1f6a elementor-widget elementor-widget-heading" data-id="e5d1f6a" data-element_type="widget" data-widget_type="heading.default">\n				<div class="elementor-widget-container">\n					<h2 class="elementor-heading-title elementor-size-default">Programa</h2>				</div>\n				</div>\n				<div class="elementor-element elementor-element-955d6f3 elementor-widget elementor-widget-text-editor" data-id="955d6f3" data-element_type="widget" data-widget_type="text-editor.default">\n				<div class="elementor-widget-container">\n									<ul><li>Tecnologías Predictivas, Tecnologías de Alerta y Tecnologías Paliativas</li><li>Presentaciones por profesionales de la salud de primera categoría, quienes compartirán las últimas novedades en neurología, terapias y tecnologías asistivas</li><li>Side events con innovadoras experiencias para fomentar el desarrollo de tecnologías en epilepsia</li></ul>								</div>\n				</div>\n				<div class="elementor-element elementor-element-a042598 elementor-align-center elementor-widget elementor-widget-button" data-id="a042598" data-element_type="widget" data-widget_type="button.default">\n				<div class="elementor-widget-container">\n									<div class="elementor-button-wrapper">\n					<a class="elementor-button elementor-button-link elementor-size-sm" href="https://docs.google.com/spreadsheets/d/1gYA-xijP7A0EusQKS8hoYKUpnq0msEdW4Ck7FTESNW0/edit#gid=414009378">\n						<span class="elementor-button-content-wrapper">\n									<span class="elementor-button-text">Ver cronograma</span>\n					</span>\n					</a>\n				</div>\n								</div>\n				</div>\n				<div class="elementor-element elementor-element-87aac25 elementor-widget elementor-widget-heading" data-id="87aac25" data-element_type="widget" data-widget_type="heading.default">\n				<div class="elementor-widget-container">\n					<h2 class="elementor-heading-title elementor-size-default">Charlas Propuestas</h2>				</div>\n				</div>\n				<div class="elementor-element elementor-element-aadbf1b elementor-widget elementor-widget-text-editor" data-id="aadbf1b" data-element_type="widget" data-widget_type="text-editor.default">\n				<div class="elementor-widget-container">\n									<ul><li>Cirugía con electrodos intracraneales en epilepsia Que es la SEEG Stereo Electro Encefalografia</li><li>“El Paso a paso de la colocación de electrodos en epilepsia” + Testimonio</li><li>“Nuevas técnicas quirúrgicas mínimamente invasivas &#8211; Realidad Argentina vs. Nivel Mundial” (LASER, Termolesión por radiofrecuencia, Robot para colocación de electrodos)</li><li>“Neuromodulación en epilepsia &#8211; Presente y Futuro + (Generalidades + VNS)” + testimonio de paciente (videos)</li><li>“DBS y RNS en epilepsia” “Tipos de dispositivos en epilepsia” &#8211; Clasificación y ejemplos</li><li>“Inteligencia Artificial y Diagnóstico en Epilepsia” Machine Learning en Epilepsia </li></ul>								</div>\n				</div>\n				<div class="elementor-element elementor-element-e4caddd elementor-widget elementor-widget-heading" data-id="e4caddd" data-element_type="widget" data-widget_type="heading.default">\n				<div class="elementor-widget-container">\n					<h2 class="elementor-heading-title elementor-size-default">¿A quiénes está destinado?</h2>				</div>\n				</div>\n				<div class="elementor-element elementor-element-737e349 elementor-widget elementor-widget-text-editor" data-id="737e349" data-element_type="widget" data-widget_type="text-editor.default">\n				<div class="elementor-widget-container">\n									<ul><li>Personas con epilepsia, familiares y amigos</li><li>Bioingenieros/as y estudiantes de bioingeniería</li><li>Profesionales de la salud</li><li>Emprendedores</li></ul>								</div>\n				</div>\n					</div>\n		</div>\n					</div>\n		</section>\n				<section class="elementor-section elementor-top-section elementor-element elementor-element-07409fa elementor-section-boxed elementor-section-height-default elementor-section-height-default" data-id="07409fa" data-element_type="section" data-settings="{&quot;background_background&quot;:&quot;classic&quot;}">\n						<div class="elementor-container elementor-column-gap-default">\n					<div class="elementor-column elementor-col-100 elementor-top-column elementor-element elementor-element-f1f31b0" data-id="f1f31b0" data-element_type="column">\n			<div class="elementor-widget-wrap elementor-element-populated">\n						<div class="elementor-element elementor-element-e251d42 elementor-widget elementor-widget-heading" data-id="e251d42" data-element_type="widget" data-widget_type="heading.default">\n				<div class="elementor-widget-container">\n					<h2 class="elementor-heading-title elementor-size-default">Inscribite al evento haciendo click acá</h2>				</div>\n				</div>\n				<div class="elementor-element elementor-element-4cda72b elementor-align-center elementor-widget elementor-widget-button" data-id="4cda72b" data-element_type="widget" data-widget_type="button.default">\n				<div class="elementor-widget-container">\n									<div class="elementor-button-wrapper">\n					<a class="elementor-button elementor-button-link elementor-size-sm" href="https://docs.google.com/forms/d/1yXR5ic4Ogrl25LEhAZl3vPW_BIRSZdRnJcJLUmcSHaA/viewform?edit_requested=true">\n						<span class="elementor-button-content-wrapper">\n									<span class="elementor-button-text">Ver más</span>\n					</span>\n					</a>\n				</div>\n								</div>\n				</div>\n					</div>\n		</div>\n					</div>\n		</section>\n				<section class="elementor-section elementor-top-section elementor-element elementor-element-d7c3e16 elementor-section-boxed elementor-section-height-default elementor-section-height-default" data-id="d7c3e16" data-element_type="section">\n						<div class="elementor-container elementor-column-gap-default">\n					<div class="elementor-column elementor-col-100 elementor-top-column elementor-element elementor-element-90db0e0" data-id="90db0e0" data-element_type="column">\n			<div class="elementor-widget-wrap elementor-element-populated">\n						<div class="elementor-element elementor-element-2344c6d elementor-widget elementor-widget-heading" data-id="2344c6d" data-element_type="widget" data-widget_type="heading.default">\n				<div class="elementor-widget-container">\n					<h2 class="elementor-heading-title elementor-size-default">¿Cómo apoyar esta iniciativa?</h2>				</div>\n				</div>\n				<div class="elementor-element elementor-element-70f1b8c elementor-widget elementor-widget-text-editor" data-id="70f1b8c" data-element_type="widget" data-widget_type="text-editor.default">\n				<div class="elementor-widget-container">\n									<p><strong>Ayudá a difundir el evento: </strong><br /><br />Auspiciante Sumate a la difusión de techsia para que más personas se puedan beneficiar. Te mandaremos material de difusión para que compartas por e-mail y/o en redes sociales. </p><p><strong>Apoyo:</strong> Este evento cuenta con el apoyo del Hospital FLENI y la Liga Argentina Contra la Epilepsia (LACE), miembro de la International League Againt Epilepsy (ILAE) contacto@espacioepilepsia.</p>								</div>\n				</div>\n					</div>\n		</div>\n					</div>\n		</section>\n				</div>\n		', 'El simposio de Tecnología y epilepsia ¡Hola! Desde Espacio Epilepsia, nos alegra muchísimo anunciar que llega primer simposio de Tecnología y epilepsia Techsia!. 25 de Agosto de 2023PRESENCIAL Y GRATUITO  Sobre Techsia Techsia es un evento que tiene la finalidad de difundir tecnologías vinculadas a la epilepsia en la comunidad, propone espacios de conversación entre [&hellip;]\n', 'blog', '2023-07-24T11:22:53', true, 'https://espacioepilepsia.org/wp-content/uploads/2023/07/1_eventos.jpeg'),
('Epifest: Primer Congreso Internacional de Epilepsia para la Comunidad', 'epifest', '		<div data-elementor-type="wp-post" data-elementor-id="822" class="elementor elementor-822" data-elementor-post-type="post">\n						<section class="elementor-section elementor-top-section elementor-element elementor-element-5eb10f7 elementor-section-boxed elementor-section-height-default elementor-section-height-default" data-id="5eb10f7" data-element_type="section" data-settings="{&quot;background_background&quot;:&quot;classic&quot;}">\n						<div class="elementor-container elementor-column-gap-default">\n					<div class="elementor-column elementor-col-100 elementor-top-column elementor-element elementor-element-957eee9" data-id="957eee9" data-element_type="column">\n			<div class="elementor-widget-wrap elementor-element-populated">\n						<div class="elementor-element elementor-element-6e1df34 elementor-widget elementor-widget-theme-post-title elementor-page-title elementor-widget-heading" data-id="6e1df34" data-element_type="widget" data-widget_type="theme-post-title.default">\n				<div class="elementor-widget-container">\n					<h1 class="elementor-heading-title elementor-size-default">Epifest: Primer Congreso Internacional de Epilepsia para la Comunidad</h1>				</div>\n				</div>\n					</div>\n		</div>\n					</div>\n		</section>\n				<section class="elementor-section elementor-top-section elementor-element elementor-element-07bc4b7 elementor-section-boxed elementor-section-height-default elementor-section-height-default" data-id="07bc4b7" data-element_type="section">\n						<div class="elementor-container elementor-column-gap-default">\n					<div class="elementor-column elementor-col-100 elementor-top-column elementor-element elementor-element-0a591f2" data-id="0a591f2" data-element_type="column">\n			<div class="elementor-widget-wrap elementor-element-populated">\n						<div class="elementor-element elementor-element-9a2ddf2 elementor-widget elementor-widget-image" data-id="9a2ddf2" data-element_type="widget" data-widget_type="image.default">\n				<div class="elementor-widget-container">\n															<img decoding="async" width="768" height="768" src="https://espacioepilepsia.org/wp-content/uploads/2023/05/7-blog-768x768.webp" class="attachment-medium_large size-medium_large wp-image-824" alt="" srcset="https://espacioepilepsia.org/wp-content/uploads/2023/05/7-blog-768x768.webp 768w, https://espacioepilepsia.org/wp-content/uploads/2023/05/7-blog-300x300.webp 300w, https://espacioepilepsia.org/wp-content/uploads/2023/05/7-blog-100x100.webp 100w, https://espacioepilepsia.org/wp-content/uploads/2023/05/7-blog-600x600.webp 600w, https://espacioepilepsia.org/wp-content/uploads/2023/05/7-blog-1024x1024.webp 1024w, https://espacioepilepsia.org/wp-content/uploads/2023/05/7-blog-150x150.webp 150w, https://espacioepilepsia.org/wp-content/uploads/2023/05/7-blog.webp 1480w" sizes="(max-width: 768px) 100vw, 768px" />															</div>\n				</div>\n				<div class="elementor-element elementor-element-035d772 elementor-widget elementor-widget-text-editor" data-id="035d772" data-element_type="widget" data-widget_type="text-editor.default">\n				<div class="elementor-widget-container">\n									<p id="viewer-8tqbr" class="mm8Nw _1j-51 WkT0MK _1FoOD _3M0Fe T3Ond1 WkT0MK public-DraftStyleDefault-block-depth0 fixed-tab-size public-DraftStyleDefault-text-ltr"><span class="_2PHJq public-DraftStyleDefault-ltr">La comunidad virtual Espacio Epilepsia y la Liga Argentina Contra la Epilepsia (LACE) se complacen en anunciar la primera edición del <a class="_3Bkfb _1lsz7" href="http://www.epifest.com/" target="_blank" rel="noopener noreferrer" data-hook="linkViewer"><strong><u class="_3zM-5">epifest</u></strong></a><strong>!</strong>, un congreso dirigido a la comunidad alrededor de la epilepsia. El propósito de <a class="_3Bkfb _1lsz7" href="http://www.epifest.com/" target="_blank" rel="noopener noreferrer" data-hook="linkViewer"><strong><u class="_3zM-5">epifest</u></strong></a><strong>!</strong> es reunir los últimos avances científicos y la experiencia de las personas con epilepsia, incluyéndolas desde su diseño, organización y contenido.</span></p><p id="viewer-5jgvk" class="mm8Nw _1j-51 WkT0MK _1FoOD _3M0Fe T3Ond1 WkT0MK public-DraftStyleDefault-block-depth0 fixed-tab-size public-DraftStyleDefault-text-ltr"><span class="_2PHJq public-DraftStyleDefault-ltr"><a class="_3Bkfb _1lsz7" href="http://www.epifest.com/" target="_blank" rel="noopener noreferrer" data-hook="linkViewer"><strong><u class="_3zM-5">epifest</u></strong></a><strong>!</strong> se realizará de modo 100% virtual y gratuito, entre el 17 y el 19 de marzo y culminará con un cierre el 26 de marzo (coincidiendo con Purple Day).</span></p>								</div>\n				</div>\n				<div class="elementor-element elementor-element-c15914b elementor-widget elementor-widget-heading" data-id="c15914b" data-element_type="widget" data-widget_type="heading.default">\n				<div class="elementor-widget-container">\n					<h2 class="elementor-heading-title elementor-size-default">Programa</h2>				</div>\n				</div>\n				<div class="elementor-element elementor-element-cfae861 elementor-widget elementor-widget-text-editor" data-id="cfae861" data-element_type="widget" data-widget_type="text-editor.default">\n				<div class="elementor-widget-container">\n									<p id="viewer-4j9ob" class="mm8Nw _1j-51 WkT0MK _1FoOD _3M0Fe T3Ond1 WkT0MK public-DraftStyleDefault-block-depth0 fixed-tab-size public-DraftStyleDefault-text-ltr"><span class="_2PHJq public-DraftStyleDefault-ltr">El programa del <a class="_3Bkfb _1lsz7" href="http://www.epifest.com/" target="_blank" rel="noopener noreferrer" data-hook="linkViewer"><strong><u class="_3zM-5">epifest</u></strong></a><strong>!</strong> brindará herramientas para mejorar la calidad de vida y reducir los estigmas alrededor de la epilepsia. El congreso incluye:</span></p><ul><li id="viewer-4j9ob" class="mm8Nw _1j-51 WkT0MK _1FoOD _3M0Fe T3Ond1 WkT0MK public-DraftStyleDefault-block-depth0 fixed-tab-size public-DraftStyleDefault-text-ltr"><span style="background-color: var(--ast-global-color-5); color: var( --e-global-color-text ); font-style: inherit; font-weight: inherit; font-size: 1rem;">charlas centradas en la vida de las personas con epilepsia;</span></li><li id="viewer-9kgo2" class="mm8Nw _1j-51 WkT0MK _1FoOD _3M0Fe T3Ond1 WkT0MK public-DraftStyleDefault-block-depth0 fixed-tab-size public-DraftStyleDefault-text-ltr"><span style="background-color: var(--ast-global-color-5); color: var( --e-global-color-text ); font-style: inherit; font-weight: inherit; font-size: 1rem;">presentaciones por profesionales de la salud de primera categoría, quienes compartirán las últimas novedades en neurología, terapias y tecnologías asistivas;</span></li><li id="viewer-50fik" class="mm8Nw _1j-51 WkT0MK _1FoOD _3M0Fe T3Ond1 WkT0MK public-DraftStyleDefault-block-depth0 fixed-tab-size public-DraftStyleDefault-text-ltr"><span class="_2PHJq public-DraftStyleDefault-ltr"> y talleres innovadores y actividades participativas creados por y para la comunidad.</span></li></ul>								</div>\n				</div>\n				<div class="elementor-element elementor-element-e63ed22 elementor-widget elementor-widget-text-editor" data-id="e63ed22" data-element_type="widget" data-widget_type="text-editor.default">\n				<div class="elementor-widget-container">\n									<p id="viewer-4gogc" class="mm8Nw _1j-51 WkT0MK _1FoOD _3M0Fe T3Ond1 WkT0MK public-DraftStyleDefault-block-depth0 fixed-tab-size public-DraftStyleDefault-text-ltr"><span class="_2PHJq public-DraftStyleDefault-ltr"><a class="_3Bkfb _1lsz7" href="http://www.epifest.com/" target="_blank" rel="noopener noreferrer" data-hook="linkViewer"><strong><u class="_3zM-5">epifest</u></strong></a><strong>!</strong> propone actividades online para una participación dinámica que promueva, además de la circulación de información, la producción de nuevos aprendizajes. También se fomentará la interacción desde la comunidad con concursos y una premiación al mejor activista online de epilepsia.<br /></span><span style="color: var( --e-global-color-text ); font-weight: inherit; font-size: 1rem; font-style: inherit; background-color: var(--ast-global-color-5);"><br />La realización del </span><a class="_3Bkfb _1lsz7" style="font-weight: inherit; font-size: 1rem; font-style: inherit;" href="http://www.epifest.com/" target="_blank" rel="noopener noreferrer" data-hook="linkViewer"><strong><u class="_3zM-5">epifest</u></strong></a><strong style="color: var( --e-global-color-text ); font-size: 1rem; font-style: inherit; background-color: var(--ast-global-color-5);">!</strong><span style="color: var( --e-global-color-text ); font-weight: inherit; font-size: 1rem; font-style: inherit; background-color: var(--ast-global-color-5);"> marcará la culminación de varias semanas que la comunidad dedica a generar atención para los desafíos que enfrentan; comenzando el segundo lunes de febrero con el Día Internacional de la Epilepsia, con el cual se promueve la concientización por los derechos de las personas con epilepsia, y finalizando el 26 de marzo con el Purple Day, otra fecha observada internacionalmente, cuyo fin es combatir los mitos relacionados a la epilepsia.</span></p><div data-hook="rcv-block14"><span style="color: var( --e-global-color-text ); font-weight: inherit; font-size: 1rem; font-style: inherit; background-color: var(--ast-global-color-5);">Para más información e inscripciones, visitar </span><a class="_3Bkfb _1lsz7" style="font-weight: inherit; font-size: 1rem; font-style: inherit;" href="http://www.epifest.com/" target="_blank" rel="noopener noreferrer" data-hook="linkViewer">www.epifest.com</a></div>								</div>\n				</div>\n				<div class="elementor-element elementor-element-e618190 elementor-widget-divider--view-line elementor-widget elementor-widget-divider" data-id="e618190" data-element_type="widget" data-widget_type="divider.default">\n				<div class="elementor-widget-container">\n							<div class="elementor-divider">\n			<span class="elementor-divider-separator">\n						</span>\n		</div>\n						</div>\n				</div>\n				<div class="elementor-element elementor-element-53f171c elementor-widget elementor-widget-heading" data-id="53f171c" data-element_type="widget" data-widget_type="heading.default">\n				<div class="elementor-widget-container">\n					<h3 class="elementor-heading-title elementor-size-default">Por Espacio Epilepsia</h3>				</div>\n				</div>\n					</div>\n		</div>\n					</div>\n		</section>\n				</div>\n		', 'La comunidad virtual Espacio Epilepsia y la Liga Argentina Contra la Epilepsia (LACE) se complacen en anunciar la primera edición del epifest!, un congreso dirigido a la comunidad alrededor de la epilepsia. El propósito de epifest! es reunir los últimos avances científicos y la experiencia de las personas con epilepsia, incluyéndolas desde su diseño, organización [&hellip;]\n', 'blog', '2023-05-06T19:33:17', true, 'https://espacioepilepsia.org/wp-content/uploads/2023/05/7-blog.webp'),
('Donación de Sangre y Epilepsia', 'donacionsangre', '		<div data-elementor-type="wp-post" data-elementor-id="802" class="elementor elementor-802" data-elementor-post-type="post">\n						<section class="elementor-section elementor-top-section elementor-element elementor-element-5eb10f7 elementor-section-boxed elementor-section-height-default elementor-section-height-default" data-id="5eb10f7" data-element_type="section" data-settings="{&quot;background_background&quot;:&quot;classic&quot;}">\n						<div class="elementor-container elementor-column-gap-default">\n					<div class="elementor-column elementor-col-100 elementor-top-column elementor-element elementor-element-957eee9" data-id="957eee9" data-element_type="column">\n			<div class="elementor-widget-wrap elementor-element-populated">\n						<div class="elementor-element elementor-element-6e1df34 elementor-widget elementor-widget-theme-post-title elementor-page-title elementor-widget-heading" data-id="6e1df34" data-element_type="widget" data-widget_type="theme-post-title.default">\n				<div class="elementor-widget-container">\n					<h1 class="elementor-heading-title elementor-size-default">Donación de Sangre y Epilepsia</h1>				</div>\n				</div>\n					</div>\n		</div>\n					</div>\n		</section>\n				<section class="elementor-section elementor-top-section elementor-element elementor-element-07bc4b7 elementor-section-boxed elementor-section-height-default elementor-section-height-default" data-id="07bc4b7" data-element_type="section">\n						<div class="elementor-container elementor-column-gap-default">\n					<div class="elementor-column elementor-col-100 elementor-top-column elementor-element elementor-element-0a591f2" data-id="0a591f2" data-element_type="column">\n			<div class="elementor-widget-wrap elementor-element-populated">\n						<div class="elementor-element elementor-element-035d772 elementor-widget elementor-widget-text-editor" data-id="035d772" data-element_type="widget" data-widget_type="text-editor.default">\n				<div class="elementor-widget-container">\n									<p id="viewer-foo" class="mm8Nw _1j-51 WkT0MK _1FoOD _3M0Fe T3Ond1 WkT0MK public-DraftStyleDefault-block-depth0 fixed-tab-size public-DraftStyleDefault-text-ltr">En Argentina, según La Guía de donación de sangre del año 2016 del Ministerio de la Nación, las personas con epilepsia se encuentran excluidas como donantes de sangre, salvo que cumplan con el criterio de permanecer libre de crisis por más de 3 años y no estén bajo medicación anticonvulsivante. Si están bajo tratamiento la exclusión es definitiva.</p>								</div>\n				</div>\n				<div class="elementor-element elementor-element-9a2ddf2 elementor-widget elementor-widget-image" data-id="9a2ddf2" data-element_type="widget" data-widget_type="image.default">\n				<div class="elementor-widget-container">\n															<img decoding="async" width="768" height="433" src="https://espacioepilepsia.org/wp-content/uploads/2023/05/5-blog-768x433.webp" class="attachment-medium_large size-medium_large wp-image-804" alt="" srcset="https://espacioepilepsia.org/wp-content/uploads/2023/05/5-blog-768x433.webp 768w, https://espacioepilepsia.org/wp-content/uploads/2023/05/5-blog-600x338.webp 600w, https://espacioepilepsia.org/wp-content/uploads/2023/05/5-blog-300x169.webp 300w, https://espacioepilepsia.org/wp-content/uploads/2023/05/5-blog-1024x577.webp 1024w, https://espacioepilepsia.org/wp-content/uploads/2023/05/5-blog.webp 1480w" sizes="(max-width: 768px) 100vw, 768px" />															</div>\n				</div>\n				<div class="elementor-element elementor-element-cfae861 elementor-widget elementor-widget-text-editor" data-id="cfae861" data-element_type="widget" data-widget_type="text-editor.default">\n				<div class="elementor-widget-container">\n									<p id="viewer-3q0ae" class="mm8Nw _1j-51 WkT0MK _1FoOD _3M0Fe T3Ond1 WkT0MK public-DraftStyleDefault-block-depth0 fixed-tab-size public-DraftStyleDefault-text-ltr"><span class="_2PHJq public-DraftStyleDefault-ltr">En muchos países, como el nuestro, las personas con epilepsia son excluidas definitiva o temporalmente como donantes de sangre, y según nuestro conocimiento esto puede deberse a dos preocupaciones:<br /></span><span style="color: var( --e-global-color-text ); font-size: 1rem; font-style: inherit; background-color: var(--ast-global-color-5);"><br /><b>a.</b></span><span style="color: var( --e-global-color-text ); font-weight: inherit; font-size: 1rem; font-style: inherit; background-color: var(--ast-global-color-5);"> Que los donantes con epilepsia pudieran tener mayores reacciones adversas durante el procedimiento de la donación de sangre en comparación con otros donantes sin epilepsia. <br /></span><strong style="color: var( --e-global-color-text ); font-size: 1rem; font-style: inherit; background-color: var(--ast-global-color-5);">b.</strong><span style="color: var( --e-global-color-text ); font-weight: inherit; font-size: 1rem; font-style: inherit; background-color: var(--ast-global-color-5);"> Que las medicaciones anticonvulsivantes pudieran provocar alguna reacción adversa en el receptor del componente sanguíneo</span></p><div data-hook="rcv-block7"> <span style="font-style: inherit; font-weight: inherit; color: var( --e-global-color-text ); background-color: var(--ast-global-color-5);">Existen estudios que evalúan la seguridad del proceso de donación en pacientes con epilepsia. En 1988, Krumholz y cols. (Ref 1), publicaron un reporte de 297 donaciones de sangre por personas con epilepsia y no evidenciaron efectos adversos mayores que lo reportado habitualmente para la población en general. En 1995, Kellens y cols (Ref.2) realizaron un estudio prospectivo caso/control. En 329.143 donaciones, 723 fueron realizadas por personas con epilepsia, quienes no tuvieron una incidencia mayor de efectos adversos en general, ni de síncopes en particular comparado al grupo control.</span></div><div data-hook="rcv-block8"> </div><p id="viewer-3dc9r" class="mm8Nw _1j-51 WkT0MK _1FoOD _3M0Fe T3Ond1 WkT0MK public-DraftStyleDefault-block-depth0 fixed-tab-size public-DraftStyleDefault-text-ltr"><span class="_2PHJq public-DraftStyleDefault-ltr"> En el año 2000, Illies y Cols (Ref.3) publicaron un estudio documentando 50 donaciones en 26 pacientes con epilepsia REFRACTARIA, 25 de ellos tomaba medicación. La mayoría de los pacientes NO tenían su epilepsia controlada, eran formas refractarias y aún bajo esta condición no presentaron efectos adversos diferentes a la población en general. En el año 2017, se publicó una revisión sistemática (ref. 4) acerca de la seguridad de las personas con epilepsia en la donación de sangre. La conclusión fue que ningún estudio pudo demostrar que las personas con epilepsia tengan mayor riesgo de efectos adversos. Ninguno de los estudios reportó crisis epilépticas durante el proceso de donación de sangre. </span></p><div data-hook="rcv-block9"> <span style="font-style: inherit; font-weight: inherit; color: var( --e-global-color-text ); background-color: var(--ast-global-color-5);">La conclusión global de los estudios que analizan el tema (Ref.5) es que la restricción a la donación de sangre a los pacientes con epilepsia podría estar basada en la confusión o malinterpretación entre el síncope y la convulsión. Dado que ambos eventos se presentan en forma súbita, con pérdida de la conciencia y entre el 40–50% de los síncopes cursan con sacudidas o hipertonía. Esto genera en el observador la presunción errónea de que se trata de una crisis epiléptica. No está descripto que los pacientes con epilepsia tengan una mayor predisposición a presentar síncopes. Algunos pacientes con epilepsia pueden presentar convulsiones provocadas por determinados estímulos (visuales, auditivos, inmersión en agua caliente, etc) La donación de sangre no está descripta como un factor desencadenante de crisis epilépticas.</span></div><div data-hook="rcv-block10"> </div><p id="viewer-fjtiu" class="mm8Nw _1j-51 WkT0MK _1FoOD _3M0Fe T3Ond1 WkT0MK public-DraftStyleDefault-block-depth0 fixed-tab-size public-DraftStyleDefault-text-ltr"><span class="_2PHJq public-DraftStyleDefault-ltr">La guía de criterios para la selección de donantes de sangre del ministerio de salud del 2016, en el apartado de MEDICAMENTOS, informa: “en general los medicamentos tomados por el donante no representan riesgo para el receptor”. La mayoría de los medicamentos tendrá una concentración mínima en la unidad de sangre. Las trazas o restos de medicación presentes en los componentes sanguíneos son inocuos para los receptores, por eso las personas que toman medicamentos pueden ser aceptados como donantes. En la sección de la guía que hace referencia a los ANTICONVULSIVANTES aclara que éstos no contraindican la donación si están siendo utilizados por ejemplo para el tratamiento del dolor.</span></p>								</div>\n				</div>\n				<div class="elementor-element elementor-element-b3a3129 elementor-widget elementor-widget-image" data-id="b3a3129" data-element_type="widget" data-widget_type="image.default">\n				<div class="elementor-widget-container">\n															<img loading="lazy" decoding="async" width="768" height="768" src="https://espacioepilepsia.org/wp-content/uploads/2023/05/6-blog-768x768.png" class="attachment-medium_large size-medium_large wp-image-812" alt="" srcset="https://espacioepilepsia.org/wp-content/uploads/2023/05/6-blog-768x768.png 768w, https://espacioepilepsia.org/wp-content/uploads/2023/05/6-blog-300x300.png 300w, https://espacioepilepsia.org/wp-content/uploads/2023/05/6-blog-100x100.png 100w, https://espacioepilepsia.org/wp-content/uploads/2023/05/6-blog-600x600.png 600w, https://espacioepilepsia.org/wp-content/uploads/2023/05/6-blog-1024x1024.png 1024w, https://espacioepilepsia.org/wp-content/uploads/2023/05/6-blog-150x150.png 150w, https://espacioepilepsia.org/wp-content/uploads/2023/05/6-blog.png 1080w" sizes="(max-width: 768px) 100vw, 768px" />															</div>\n				</div>\n				<div class="elementor-element elementor-element-e63ed22 elementor-widget elementor-widget-text-editor" data-id="e63ed22" data-element_type="widget" data-widget_type="text-editor.default">\n				<div class="elementor-widget-container">\n									<p id="viewer-63gdl" class="mm8Nw _1j-51 WkT0MK _1FoOD _3M0Fe T3Ond1 WkT0MK public-DraftStyleDefault-block-depth0 fixed-tab-size public-DraftStyleDefault-text-ltr"><span class="_2PHJq public-DraftStyleDefault-ltr">Entendemos entonces que la preocupación acerca de que las medicaciones anticonvulsivantes afecten al receptor no sería un aspecto a tener en cuenta y la preocupación sería la seguridad del donante con epilepsia durante el proceso de la donación.</span></p><div data-hook="rcv-block14"> <span style="font-style: inherit; font-weight: inherit; color: var( --e-global-color-text ); background-color: var(--ast-global-color-5);">El hecho de diferir a las personas con epilepsia como donantes podría resultar en dos pérdidas: <br /></span><strong style="font-style: inherit; color: var( --e-global-color-text ); background-color: var(--ast-global-color-5);">a.</strong><span style="font-style: inherit; font-weight: inherit; color: var( --e-global-color-text ); background-color: var(--ast-global-color-5);"> Perder un número significativo de potenciales donantes (La prevalencia de epilepsia es del 1% en la población)</span></div><p id="viewer-d3ojd" class="mm8Nw _1j-51 WkT0MK _1FoOD _3M0Fe T3Ond1 WkT0MK public-DraftStyleDefault-block-depth0 fixed-tab-size public-DraftStyleDefault-text-ltr"><span class="_2PHJq public-DraftStyleDefault-ltr"><strong>b.</strong> La persona con epilepsia puede sentirse rechazado o estigmatizado. </span></p><p id="viewer-8j8fs" class="mm8Nw _1j-51 WkT0MK _1FoOD _3M0Fe T3Ond1 WkT0MK public-DraftStyleDefault-block-depth0 fixed-tab-size public-DraftStyleDefault-text-ltr"><span class="_2PHJq public-DraftStyleDefault-ltr">En Junio del 2021, desde la comisión directiva de la Liga Argentina Contra la Epilepsia (LACE) enviamos una solicitud a la Asociación Argentina de Hemoterapia Inmunohematologia y Terapia Celular (AAHITC) para trabajar en conjunto y revalorar el tema de la donación de sangre por personas con epilepsia. La Comisión Directiva de la AAHITC se comprometió a revisar dentro de los criterios de elegibilidad de los donantes de sangre, la aptitud para donar sangre en la población con epilepsia. Esperamos ansiosamente poder trabajar en conjunto con la AAHITC a fin de que las personas con epilepsia no sean excluidas de donar sangre.</span></p><div data-hook="rcv-block16"><em style="font-size: 16px;">Por Dra. Lorena Fasulo en colaboración con la Liga Argentina Contra la Epilepsia y Espacio Epilepsia</em></div>								</div>\n				</div>\n				<div class="elementor-element elementor-element-e618190 elementor-widget-divider--view-line elementor-widget elementor-widget-divider" data-id="e618190" data-element_type="widget" data-widget_type="divider.default">\n				<div class="elementor-widget-container">\n							<div class="elementor-divider">\n			<span class="elementor-divider-separator">\n						</span>\n		</div>\n						</div>\n				</div>\n				<div class="elementor-element elementor-element-53f171c elementor-widget elementor-widget-heading" data-id="53f171c" data-element_type="widget" data-widget_type="heading.default">\n				<div class="elementor-widget-container">\n					<h3 class="elementor-heading-title elementor-size-default">Por Dra. Lorena Fasulo en colaboración con la Liga Argentina Contra la Epilepsia y Espacio Epilepsia</h3>				</div>\n				</div>\n				<div class="elementor-element elementor-element-ac7b56a elementor-widget-divider--view-line elementor-widget elementor-widget-divider" data-id="ac7b56a" data-element_type="widget" data-widget_type="divider.default">\n				<div class="elementor-widget-container">\n							<div class="elementor-divider">\n			<span class="elementor-divider-separator">\n						</span>\n		</div>\n						</div>\n				</div>\n				<div class="elementor-element elementor-element-803579d elementor-widget elementor-widget-heading" data-id="803579d" data-element_type="widget" data-widget_type="heading.default">\n				<div class="elementor-widget-container">\n					<h2 class="elementor-heading-title elementor-size-default">Referencias</h2>				</div>\n				</div>\n				<div class="elementor-element elementor-element-3574f0a elementor-widget elementor-widget-text-editor" data-id="3574f0a" data-element_type="widget" data-widget_type="text-editor.default">\n				<div class="elementor-widget-container">\n									<p id="viewer-aapji" class="mm8Nw _1j-51 WkT0MK _1FoOD _3M0Fe T3Ond1 WkT0MK public-DraftStyleDefault-block-depth0 fixed-tab-size public-DraftStyleDefault-text-ltr"><span class="_2PHJq public-DraftStyleDefault-ltr">1. Krumholz A, Douglas D. K, Fisher Rs, Lesser RP, 1988. Adverse blood donor reactions in individuals with seizures or epilepsy: evidence that existing restrictions may be innecessary. Epilepsia 29,657. 2. Krumholz A, Ness PM, Hauser WA, Douglas DK, Gibble JW. Adverse reactions in blood donors with a history of seizures or epilepsy. Transfusion. 1995 Jun;35(6):470–4. doi: 10.1046/j.1537–2995.1995.35695288764.x. PMID: 7770896. 3. Illies G, Siaplaouras J, Lanksch W, Gutensohn K. 2000. Epilepsy is not a contraindication for autologous blood donation. Infusionstherapie und transfusionsmedizin. 27, 44–46 4. Kellens A, De Buck E, Emonds MP, Vandekerckhove P, Lagae L. Is it safe for people with epilepsy to donate blood? A systematic review. Epilepsy Res. 2018 Jan;139:143–149. doi: 10.1016/j.eplepsyres.2017.11.002. Epub 2017 Nov 23. PMID: 29174496. 5. Kellens A, De Buck E, Emonds MP, Vandekerckhove P, Lagae L. Worldwide policies on epilepsy and blood donation: a survey among blood services. Vox Sang. 2018 Feb;113(2):104–109. doi: 10.1111/vox.12618. Epub 2018 Jan 4. PMID: 29314064.</span></p><div data-hook="rcv-block22"> </div><p id="viewer-a3e7e" class="mm8Nw _1j-51 WkT0MK _1FoOD _3M0Fe T3Ond1 WkT0MK public-DraftStyleDefault-block-depth0 fixed-tab-size public-DraftStyleDefault-text-ltr"><span class="_2PHJq public-DraftStyleDefault-ltr"><em><strong>Hace un año, desde Espacio Epilepsia planteamos este tema para que sea tratado en LACE. Hoy celebramos el compromiso de LACE y la AAHITC para que podamos como personas con epilepsia donar sangre. Desde Espacio Epilepsia, nos parece importante visibilizar y ponernos en movimiento como comunidad para: PODER DONAR SANGRE, SIN ESTIGMAS. Es por ello que HOY, Martes 14 de Junio, 2022: Queremos invitarlos a USTEDES a firmar nuestra petición de </strong></em><a class="_3Bkfb _1lsz7" href="https://chng.it/zxrrh5cJkd" target="_blank" rel="noopener noreferrer" data-hook="linkViewer"><em><strong>change.org</strong></em></a><em><strong> para que las personas con epilepsia podamos DONAR SANGRE, SIN ESTIGMAS.</strong></em> </span></p>								</div>\n				</div>\n					</div>\n		</div>\n					</div>\n		</section>\n				</div>\n		', 'En Argentina, según La Guía de donación de sangre del año 2016 del Ministerio de la Nación, las personas con epilepsia se encuentran excluidas como donantes de sangre, salvo que cumplan con el criterio de permanecer libre de crisis por más de 3 años y no estén bajo medicación anticonvulsivante. Si están bajo tratamiento la [&hellip;]\n', 'blog', '2023-05-06T19:22:33', true, 'https://espacioepilepsia.org/wp-content/uploads/2023/05/5-blog.webp'),
('Uso indebido de Drogas y Epilepsia', 'drogasyepilepsia', '		<div data-elementor-type="wp-post" data-elementor-id="788" class="elementor elementor-788" data-elementor-post-type="post">\n						<section class="elementor-section elementor-top-section elementor-element elementor-element-5eb10f7 elementor-section-boxed elementor-section-height-default elementor-section-height-default" data-id="5eb10f7" data-element_type="section" data-settings="{&quot;background_background&quot;:&quot;classic&quot;}">\n						<div class="elementor-container elementor-column-gap-default">\n					<div class="elementor-column elementor-col-100 elementor-top-column elementor-element elementor-element-957eee9" data-id="957eee9" data-element_type="column">\n			<div class="elementor-widget-wrap elementor-element-populated">\n						<div class="elementor-element elementor-element-6e1df34 elementor-widget elementor-widget-theme-post-title elementor-page-title elementor-widget-heading" data-id="6e1df34" data-element_type="widget" data-widget_type="theme-post-title.default">\n				<div class="elementor-widget-container">\n					<h1 class="elementor-heading-title elementor-size-default">Uso indebido de Drogas y Epilepsia</h1>				</div>\n				</div>\n					</div>\n		</div>\n					</div>\n		</section>\n				<section class="elementor-section elementor-top-section elementor-element elementor-element-07bc4b7 elementor-section-boxed elementor-section-height-default elementor-section-height-default" data-id="07bc4b7" data-element_type="section">\n						<div class="elementor-container elementor-column-gap-default">\n					<div class="elementor-column elementor-col-100 elementor-top-column elementor-element elementor-element-0a591f2" data-id="0a591f2" data-element_type="column">\n			<div class="elementor-widget-wrap elementor-element-populated">\n						<div class="elementor-element elementor-element-035d772 elementor-widget elementor-widget-text-editor" data-id="035d772" data-element_type="widget" data-widget_type="text-editor.default">\n				<div class="elementor-widget-container">\n									<p>En el marco del día Internacional contra el uso indebido y el tráfico Ilícito de Drogas, creemos que la información con base científica y la prevención en el inicio del consumo de las mismas es clave en la comunidad. Sabemos que las drogas ilícitas y los productos químicos utilizados para confeccionarlas pueden generar crisis epilépticas y que aquellos pacientes con diagnóstico de epilepsia son mas vulnerables a presentar peoría en la frecuencia de sus crisis por consumirlas. La drogas ilícitas no están reguladas, no tienen estudios químicos en cuanto a su composición y es por esto que muchas veces pueden llevar a efectos adversos graves e incluso a la muerte.</p>								</div>\n				</div>\n				<section class="elementor-section elementor-inner-section elementor-element elementor-element-bd495ca elementor-section-boxed elementor-section-height-default elementor-section-height-default" data-id="bd495ca" data-element_type="section">\n						<div class="elementor-container elementor-column-gap-default">\n					<div class="elementor-column elementor-col-50 elementor-inner-column elementor-element elementor-element-3db4976" data-id="3db4976" data-element_type="column">\n			<div class="elementor-widget-wrap elementor-element-populated">\n						<div class="elementor-element elementor-element-9a2ddf2 elementor-widget elementor-widget-image" data-id="9a2ddf2" data-element_type="widget" data-widget_type="image.default">\n				<div class="elementor-widget-container">\n															<img loading="lazy" decoding="async" width="768" height="768" src="https://espacioepilepsia.org/wp-content/uploads/2023/05/2-blog-768x768.webp" class="attachment-medium_large size-medium_large wp-image-774" alt="" srcset="https://espacioepilepsia.org/wp-content/uploads/2023/05/2-blog-768x768.webp 768w, https://espacioepilepsia.org/wp-content/uploads/2023/05/2-blog-300x300.webp 300w, https://espacioepilepsia.org/wp-content/uploads/2023/05/2-blog-100x100.webp 100w, https://espacioepilepsia.org/wp-content/uploads/2023/05/2-blog-600x600.webp 600w, https://espacioepilepsia.org/wp-content/uploads/2023/05/2-blog-1024x1024.webp 1024w, https://espacioepilepsia.org/wp-content/uploads/2023/05/2-blog-150x150.webp 150w, https://espacioepilepsia.org/wp-content/uploads/2023/05/2-blog.webp 1080w" sizes="(max-width: 768px) 100vw, 768px" />															</div>\n				</div>\n					</div>\n		</div>\n				<div class="elementor-column elementor-col-50 elementor-inner-column elementor-element elementor-element-7e5a511" data-id="7e5a511" data-element_type="column">\n			<div class="elementor-widget-wrap elementor-element-populated">\n						<div class="elementor-element elementor-element-c15914b elementor-widget elementor-widget-heading" data-id="c15914b" data-element_type="widget" data-widget_type="heading.default">\n				<div class="elementor-widget-container">\n					<h2 class="elementor-heading-title elementor-size-default">Drogas ilícitas</h2>				</div>\n				</div>\n				<div class="elementor-element elementor-element-cfae861 elementor-widget elementor-widget-text-editor" data-id="cfae861" data-element_type="widget" data-widget_type="text-editor.default">\n				<div class="elementor-widget-container">\n									<p>En cuanto a otro tipo de drogas legales, su consumo también puede ser deletéreo para los pacientes con epilepsia, uno de los ejemplos es el alcohol. El alcohol en cantidades moderadas (ej: 1 vaso de cerveza o una copa de vino, una vez por semana) podría no afectar a los pacientes con epilepsia pero con cantidades mayores puede empeorar la frecuencia de crisis hasta 48 hs. después de ser ingerido. Asimismo la combinación de alcohol con algunas medicaciones anti crisis pueden producir efectos adversos graves.</p><p><br />En cuanto a otras drogas como la cocaína y la heroína pueden producir crisis epilépticas tanto en pacientes con diagnóstico de epilepsia como en pacientes sin diagnóstico previo. Son drogas que producen un gran abuso con necesidad de un equipo médico y de la comunidad para el tratamiento de la adicción.</p><p> </p>								</div>\n				</div>\n					</div>\n		</div>\n					</div>\n		</section>\n				<section class="elementor-section elementor-inner-section elementor-element elementor-element-c9a4788 elementor-section-boxed elementor-section-height-default elementor-section-height-default" data-id="c9a4788" data-element_type="section">\n						<div class="elementor-container elementor-column-gap-default">\n					<div class="elementor-column elementor-col-50 elementor-inner-column elementor-element elementor-element-a4fa34d" data-id="a4fa34d" data-element_type="column">\n			<div class="elementor-widget-wrap elementor-element-populated">\n						<div class="elementor-element elementor-element-e3f5931 elementor-widget elementor-widget-image" data-id="e3f5931" data-element_type="widget" data-widget_type="image.default">\n				<div class="elementor-widget-container">\n															<img loading="lazy" decoding="async" width="768" height="768" src="https://espacioepilepsia.org/wp-content/uploads/2023/05/3-blog-768x768.png" class="attachment-medium_large size-medium_large wp-image-793" alt="" srcset="https://espacioepilepsia.org/wp-content/uploads/2023/05/3-blog-768x768.png 768w, https://espacioepilepsia.org/wp-content/uploads/2023/05/3-blog-300x300.png 300w, https://espacioepilepsia.org/wp-content/uploads/2023/05/3-blog-100x100.png 100w, https://espacioepilepsia.org/wp-content/uploads/2023/05/3-blog-600x600.png 600w, https://espacioepilepsia.org/wp-content/uploads/2023/05/3-blog-1024x1024.png 1024w, https://espacioepilepsia.org/wp-content/uploads/2023/05/3-blog-150x150.png 150w, https://espacioepilepsia.org/wp-content/uploads/2023/05/3-blog.png 1080w" sizes="(max-width: 768px) 100vw, 768px" />															</div>\n				</div>\n					</div>\n		</div>\n				<div class="elementor-column elementor-col-50 elementor-inner-column elementor-element elementor-element-3fb286f" data-id="3fb286f" data-element_type="column">\n			<div class="elementor-widget-wrap elementor-element-populated">\n						<div class="elementor-element elementor-element-ff1a304 elementor-widget elementor-widget-heading" data-id="ff1a304" data-element_type="widget" data-widget_type="heading.default">\n				<div class="elementor-widget-container">\n					<h2 class="elementor-heading-title elementor-size-default">Alcohol</h2>				</div>\n				</div>\n				<div class="elementor-element elementor-element-a360eec elementor-widget elementor-widget-text-editor" data-id="a360eec" data-element_type="widget" data-widget_type="text-editor.default">\n				<div class="elementor-widget-container">\n									<p>Sabemos que el Cannabis contiene mas de 500 compuestos, el efecto del cannabis fumado en pacientes con epilepsia o sin el diagnóstico, tiene respuestas que varían de persona a persona, pero sabemos que puede producir o empeorar las crisis epilépticas en algunos casos. Actualmente están en investigación algunos de los compuestos purificados como por el ejemplo el cannabidiol (CBD), en forma de aceite, que actualmente se usa en algunos síndromes epilépticos específicos, con lo cual siempre debemos consultar a un médico antes de usarlo, ya que no es un tratamiento eficaz en todos los tipos de epilepsia y no todos los aceites pueden ser utilizados.</p>								</div>\n				</div>\n					</div>\n		</div>\n					</div>\n		</section>\n				<section class="elementor-section elementor-inner-section elementor-element elementor-element-a955f3c elementor-section-boxed elementor-section-height-default elementor-section-height-default" data-id="a955f3c" data-element_type="section">\n						<div class="elementor-container elementor-column-gap-default">\n					<div class="elementor-column elementor-col-50 elementor-inner-column elementor-element elementor-element-dbfaf45" data-id="dbfaf45" data-element_type="column">\n			<div class="elementor-widget-wrap elementor-element-populated">\n						<div class="elementor-element elementor-element-e0f5672 elementor-widget elementor-widget-image" data-id="e0f5672" data-element_type="widget" data-widget_type="image.default">\n				<div class="elementor-widget-container">\n															<img loading="lazy" decoding="async" width="768" height="768" src="https://espacioepilepsia.org/wp-content/uploads/2023/05/4-blog-768x768.webp" class="attachment-medium_large size-medium_large wp-image-794" alt="" srcset="https://espacioepilepsia.org/wp-content/uploads/2023/05/4-blog-768x768.webp 768w, https://espacioepilepsia.org/wp-content/uploads/2023/05/4-blog-300x300.webp 300w, https://espacioepilepsia.org/wp-content/uploads/2023/05/4-blog-100x100.webp 100w, https://espacioepilepsia.org/wp-content/uploads/2023/05/4-blog-600x600.webp 600w, https://espacioepilepsia.org/wp-content/uploads/2023/05/4-blog-1024x1024.webp 1024w, https://espacioepilepsia.org/wp-content/uploads/2023/05/4-blog-150x150.webp 150w, https://espacioepilepsia.org/wp-content/uploads/2023/05/4-blog.webp 1080w" sizes="(max-width: 768px) 100vw, 768px" />															</div>\n				</div>\n					</div>\n		</div>\n				<div class="elementor-column elementor-col-50 elementor-inner-column elementor-element elementor-element-ccbab1e" data-id="ccbab1e" data-element_type="column">\n			<div class="elementor-widget-wrap elementor-element-populated">\n						<div class="elementor-element elementor-element-c02f07d elementor-widget elementor-widget-heading" data-id="c02f07d" data-element_type="widget" data-widget_type="heading.default">\n				<div class="elementor-widget-container">\n					<h2 class="elementor-heading-title elementor-size-default">Cocaína y Heroína.</h2>				</div>\n				</div>\n				<div class="elementor-element elementor-element-e94b7bc elementor-widget elementor-widget-text-editor" data-id="e94b7bc" data-element_type="widget" data-widget_type="text-editor.default">\n				<div class="elementor-widget-container">\n									<p id="viewer-9ski3" class="mm8Nw _1j-51 WkT0MK _1FoOD _3M0Fe T3Ond1 WkT0MK public-DraftStyleDefault-block-depth0 fixed-tab-size public-DraftStyleDefault-text-ltr"><span class="_2PHJq public-DraftStyleDefault-ltr">Es importante que contemos con información veraz y científica al momento de utilizar cualquier compuesto químico, sea natural, legal o ilegal ya que todos pueden afectar de alguna manera nuestro organismo. </span></p><p class="mm8Nw _1j-51 WkT0MK _1FoOD _3M0Fe T3Ond1 WkT0MK public-DraftStyleDefault-block-depth0 fixed-tab-size public-DraftStyleDefault-text-ltr"><span class="_2PHJq public-DraftStyleDefault-ltr">Invitamos en este día a reflexionar sobre la prevención en la comunidad sobre el uso y abuso de estas sustancias y sus consecuencias en la salud física y mental de las personas.</span></p><div data-hook="rcv-block20"> </div><div id="viewer-d6rb7" class="mm8Nw _1j-51 WkT0MK _1FoOD _3M0Fe T3Ond1 WkT0MK public-DraftStyleDefault-block-depth0 fixed-tab-size public-DraftStyleDefault-text-ltr"> </div>								</div>\n				</div>\n					</div>\n		</div>\n					</div>\n		</section>\n				<div class="elementor-element elementor-element-e618190 elementor-widget-divider--view-line elementor-widget elementor-widget-divider" data-id="e618190" data-element_type="widget" data-widget_type="divider.default">\n				<div class="elementor-widget-container">\n							<div class="elementor-divider">\n			<span class="elementor-divider-separator">\n						</span>\n		</div>\n						</div>\n				</div>\n				<div class="elementor-element elementor-element-53f171c elementor-widget elementor-widget-heading" data-id="53f171c" data-element_type="widget" data-widget_type="heading.default">\n				<div class="elementor-widget-container">\n					<h3 class="elementor-heading-title elementor-size-default">Dra. Abril Marone para Espacio Epilepsia</h3>				</div>\n				</div>\n				<div class="elementor-element elementor-element-04443fd elementor-widget elementor-widget-heading" data-id="04443fd" data-element_type="widget" data-widget_type="heading.default">\n				<div class="elementor-widget-container">\n					<h3 class="elementor-heading-title elementor-size-default">*La Dra. Abril Marone es Médica Neuróloga del Servicio de Epilepsia de Fleni. Miembro de LACE - YES y SNA.</h3>				</div>\n				</div>\n					</div>\n		</div>\n					</div>\n		</section>\n				</div>\n		', 'En el marco del día Internacional contra el uso indebido y el tráfico Ilícito de Drogas, creemos que la información con base científica y la prevención en el inicio del consumo de las mismas es clave en la comunidad. Sabemos que las drogas ilícitas y los productos químicos utilizados para confeccionarlas pueden generar crisis epilépticas [&hellip;]\n', 'blog', '2023-05-06T19:08:12', true, NULL),
('CUD &#8211; Certificado único de discapacidad', 'cud', '		<div data-elementor-type="wp-post" data-elementor-id="786" class="elementor elementor-786" data-elementor-post-type="post">\n						<section class="elementor-section elementor-top-section elementor-element elementor-element-5eb10f7 elementor-section-boxed elementor-section-height-default elementor-section-height-default" data-id="5eb10f7" data-element_type="section" data-settings="{&quot;background_background&quot;:&quot;classic&quot;}">\n						<div class="elementor-container elementor-column-gap-default">\n					<div class="elementor-column elementor-col-100 elementor-top-column elementor-element elementor-element-957eee9" data-id="957eee9" data-element_type="column">\n			<div class="elementor-widget-wrap elementor-element-populated">\n						<div class="elementor-element elementor-element-6e1df34 elementor-widget elementor-widget-theme-post-title elementor-page-title elementor-widget-heading" data-id="6e1df34" data-element_type="widget" data-widget_type="theme-post-title.default">\n				<div class="elementor-widget-container">\n					<h1 class="elementor-heading-title elementor-size-default">CUD &#8211; Certificado único de discapacidad</h1>				</div>\n				</div>\n					</div>\n		</div>\n					</div>\n		</section>\n				<section class="elementor-section elementor-top-section elementor-element elementor-element-07bc4b7 elementor-section-boxed elementor-section-height-default elementor-section-height-default" data-id="07bc4b7" data-element_type="section">\n						<div class="elementor-container elementor-column-gap-default">\n					<div class="elementor-column elementor-col-100 elementor-top-column elementor-element elementor-element-0a591f2" data-id="0a591f2" data-element_type="column">\n			<div class="elementor-widget-wrap elementor-element-populated">\n						<div class="elementor-element elementor-element-9a2ddf2 elementor-widget elementor-widget-image" data-id="9a2ddf2" data-element_type="widget" data-widget_type="image.default">\n				<div class="elementor-widget-container">\n															<img loading="lazy" decoding="async" width="300" height="300" src="https://espacioepilepsia.org/wp-content/uploads/2023/05/1-blog-300x300.png" class="attachment-medium size-medium wp-image-744" alt="" srcset="https://espacioepilepsia.org/wp-content/uploads/2023/05/1-blog-300x300.png 300w, https://espacioepilepsia.org/wp-content/uploads/2023/05/1-blog-100x100.png 100w, https://espacioepilepsia.org/wp-content/uploads/2023/05/1-blog-600x600.png 600w, https://espacioepilepsia.org/wp-content/uploads/2023/05/1-blog-1024x1024.png 1024w, https://espacioepilepsia.org/wp-content/uploads/2023/05/1-blog-150x150.png 150w, https://espacioepilepsia.org/wp-content/uploads/2023/05/1-blog-768x768.png 768w, https://espacioepilepsia.org/wp-content/uploads/2023/05/1-blog.png 1080w" sizes="(max-width: 300px) 100vw, 300px" />															</div>\n				</div>\n				<div class="elementor-element elementor-element-035d772 elementor-widget elementor-widget-text-editor" data-id="035d772" data-element_type="widget" data-widget_type="text-editor.default">\n				<div class="elementor-widget-container">\n									<p id="viewer-foo" class="mm8Nw _1j-51 WkT0MK _1FoOD _3M0Fe T3Ond1 WkT0MK public-DraftStyleDefault-block-depth0 fixed-tab-size public-DraftStyleDefault-text-ltr"><span class="_2PHJq public-DraftStyleDefault-ltr">A continuación brindamos una serie de preguntas y respuestas sobre el Certificado Único de discapacidad que aplican a <u class="_3zM-5">Argentina.</u></span></p>								</div>\n				</div>\n				<div class="elementor-element elementor-element-c15914b elementor-widget elementor-widget-heading" data-id="c15914b" data-element_type="widget" data-widget_type="heading.default">\n				<div class="elementor-widget-container">\n					<h2 class="elementor-heading-title elementor-size-default">¿Que es el Certificado Único de Discapacidad (CUD)?</h2>				</div>\n				</div>\n				<div class="elementor-element elementor-element-cfae861 elementor-widget elementor-widget-text-editor" data-id="cfae861" data-element_type="widget" data-widget_type="text-editor.default">\n				<div class="elementor-widget-container">\n									<p>El CUD es un documento que certifica la discapacidad de la persona y le permite acceder a derechos y prestaciones que brinda el Estado. Es un documento público que tiene validez en todo el país.</p>								</div>\n				</div>\n				<div class="elementor-element elementor-element-a53d095 elementor-widget elementor-widget-heading" data-id="a53d095" data-element_type="widget" data-widget_type="heading.default">\n				<div class="elementor-widget-container">\n					<h2 class="elementor-heading-title elementor-size-default">¿Quién emite este certificado? ¿Cuál es su costo?</h2>				</div>\n				</div>\n				<div class="elementor-element elementor-element-57cd9f3 elementor-widget elementor-widget-text-editor" data-id="57cd9f3" data-element_type="widget" data-widget_type="text-editor.default">\n				<div class="elementor-widget-container">\n									<p>La evaluación es realizada por una Junta Evaluadora interdisciplinaria que determina si corresponde la emisión del Certificado Único de Discapacidad. Su tramitación es voluntaria y gratuita.</p>								</div>\n				</div>\n				<div class="elementor-element elementor-element-174f20b elementor-widget elementor-widget-heading" data-id="174f20b" data-element_type="widget" data-widget_type="heading.default">\n				<div class="elementor-widget-container">\n					<h2 class="elementor-heading-title elementor-size-default">¿A quiénes se lo otorga?</h2>				</div>\n				</div>\n				<div class="elementor-element elementor-element-b1ba97e elementor-widget elementor-widget-text-editor" data-id="b1ba97e" data-element_type="widget" data-widget_type="text-editor.default">\n				<div class="elementor-widget-container">\n									<p>La evaluación es realizada por una Junta Evaluadora interdisciplinaria que determina si corresponde la emisión del Certificado Único de Discapacidad. Su tramitación es voluntaria y gratuita.</p>								</div>\n				</div>\n				<div class="elementor-element elementor-element-f3932aa elementor-widget elementor-widget-heading" data-id="f3932aa" data-element_type="widget" data-widget_type="heading.default">\n				<div class="elementor-widget-container">\n					<h2 class="elementor-heading-title elementor-size-default">¿A dónde debo realizar el trámite? ¿Qué documentación debo presentar?</h2>				</div>\n				</div>\n				<div class="elementor-element elementor-element-8fdca79 elementor-widget elementor-widget-text-editor" data-id="8fdca79" data-element_type="widget" data-widget_type="text-editor.default">\n				<div class="elementor-widget-container">\n									<p id="viewer-5lts" class="mm8Nw _1j-51 WkT0MK _1FoOD _3M0Fe T3Ond1 WkT0MK public-DraftStyleDefault-block-depth0 fixed-tab-size public-DraftStyleDefault-text-ltr"><span class="_2PHJq public-DraftStyleDefault-ltr">Acercate a la dependencia provincial de discapacidad dependiente del Ministerio de Salud de la </span><span class="_2PHJq public-DraftStyleDefault-ltr">provincia donde residís (algunas cuentan con varias sedes en distintas localidades). Acercate y </span><span class="_2PHJq public-DraftStyleDefault-ltr">asesorate acerca de la documentación que debes presentar para que te puedan otorgar un turno y </span><span class="_2PHJq public-DraftStyleDefault-ltr">empezar el trámite.</span></p>								</div>\n				</div>\n				<div class="elementor-element elementor-element-93bddfd elementor-widget elementor-widget-heading" data-id="93bddfd" data-element_type="widget" data-widget_type="heading.default">\n				<div class="elementor-widget-container">\n					<h2 class="elementor-heading-title elementor-size-default">¿El CUD tiene vencimiento? ¿Cada cuánto tiempo debo renovar el CUD?</h2>				</div>\n				</div>\n				<div class="elementor-element elementor-element-4a240ea elementor-widget elementor-widget-text-editor" data-id="4a240ea" data-element_type="widget" data-widget_type="text-editor.default">\n				<div class="elementor-widget-container">\n									<p>El certificado tiene fecha de vencimiento, la duración del mismo lo evalúa la Junta Evaluadora Interdisciplinaria al momento de la evaluación.</p>								</div>\n				</div>\n				<div class="elementor-element elementor-element-49ec832 elementor-widget elementor-widget-heading" data-id="49ec832" data-element_type="widget" data-widget_type="heading.default">\n				<div class="elementor-widget-container">\n					<h2 class="elementor-heading-title elementor-size-default">¿Me afecta en algo poseer CUD?</h2>				</div>\n				</div>\n				<div class="elementor-element elementor-element-7fdb04f elementor-widget elementor-widget-text-editor" data-id="7fdb04f" data-element_type="widget" data-widget_type="text-editor.default">\n				<div class="elementor-widget-container">\n									<p id="viewer-4h7cf" class="mm8Nw _1j-51 WkT0MK _1FoOD _3M0Fe T3Ond1 WkT0MK public-DraftStyleDefault-block-depth0 fixed-tab-size public-DraftStyleDefault-text-ltr"><span class="_2PHJq public-DraftStyleDefault-ltr">El Certificado no afecta a la vida civil de la persona; no tiene relación con el porcentaje de </span><span class="_2PHJq public-DraftStyleDefault-ltr">discapacidad, ni con la declaración judicial de insania o inhabilitación que determina la </span><span class="_2PHJq public-DraftStyleDefault-ltr">designación de un curador.</span></p>								</div>\n				</div>\n				<div class="elementor-element elementor-element-8ea3fd7 elementor-widget elementor-widget-heading" data-id="8ea3fd7" data-element_type="widget" data-widget_type="heading.default">\n				<div class="elementor-widget-container">\n					<h2 class="elementor-heading-title elementor-size-default">¿Que hago si me niegan el CUD?</h2>				</div>\n				</div>\n				<div class="elementor-element elementor-element-e63ed22 elementor-widget elementor-widget-text-editor" data-id="e63ed22" data-element_type="widget" data-widget_type="text-editor.default">\n				<div class="elementor-widget-container">\n									<p id="viewer-bsuoc" class="mm8Nw _1j-51 WkT0MK _1FoOD _3M0Fe T3Ond1 WkT0MK public-DraftStyleDefault-block-depth0 fixed-tab-size public-DraftStyleDefault-text-ltr"><span class="_2PHJq public-DraftStyleDefault-ltr">Si te negaron el CUD, podés presentar un reclamo ante la Junta Evaluadora (o ante el organismo </span><span class="_2PHJq public-DraftStyleDefault-ltr">encargado del otorgamiento del CUD en tu provincia) que te lo negó, o interponer una acción </span><span class="_2PHJq public-DraftStyleDefault-ltr">judicial. Aunque la acción judicial se puede intentar sin necesidad de recurrir a la Junta, se </span><span class="_2PHJq public-DraftStyleDefault-ltr">recomienda reclamar primero ante ella y, solo si ese reclamo no resuelve la situación, acudir a la </span><span class="_2PHJq public-DraftStyleDefault-ltr">Justicia.</span></p>								</div>\n				</div>\n				<div class="elementor-element elementor-element-803579d elementor-widget elementor-widget-heading" data-id="803579d" data-element_type="widget" data-widget_type="heading.default">\n				<div class="elementor-widget-container">\n					<h2 class="elementor-heading-title elementor-size-default">¡NO OLVIDES!</h2>				</div>\n				</div>\n				<div class="elementor-element elementor-element-3574f0a elementor-widget elementor-widget-text-editor" data-id="3574f0a" data-element_type="widget" data-widget_type="text-editor.default">\n				<div class="elementor-widget-container">\n									<p id="viewer-8ug04" class="mm8Nw _1j-51 WkT0MK _1FoOD _3M0Fe T3Ond1 WkT0MK public-DraftStyleDefault-block-depth0 fixed-tab-size public-DraftStyleDefault-text-ltr"><span class="_2PHJq public-DraftStyleDefault-ltr">Acudí siempre a tu neuróloga/o de referencia que viene realizando tu seguimiento, </span><span class="_2PHJq public-DraftStyleDefault-ltr">cualquier planilla debe ser completado por tu médico/a! </span><span class="_2PHJq public-DraftStyleDefault-ltr">Si el CUD lo necesitas por la prestación de tus medicamentos y no te lo otorgan, el sistema </span><span class="_2PHJq public-DraftStyleDefault-ltr">público (hospitales, centros de salud, etc.) deben garantizar la atención de tu salud y el </span><span class="_2PHJq public-DraftStyleDefault-ltr">acceso a tus medicamentos y si la dificultad es ante la obra social, tené en cuenta la ley de epilepsia (25.404) </span><span class="_2PHJq public-DraftStyleDefault-ltr">para hacer los reclamos correspondientes!</span></p>								</div>\n				</div>\n				<div class="elementor-element elementor-element-53f171c elementor-widget elementor-widget-heading" data-id="53f171c" data-element_type="widget" data-widget_type="heading.default">\n				<div class="elementor-widget-container">\n					<h3 class="elementor-heading-title elementor-size-default">Por María Julia Caterina* para Espacio Epilepsia</h3>				</div>\n				</div>\n				<div class="elementor-element elementor-element-e618190 elementor-widget-divider--view-line elementor-widget elementor-widget-divider" data-id="e618190" data-element_type="widget" data-widget_type="divider.default">\n				<div class="elementor-widget-container">\n							<div class="elementor-divider">\n			<span class="elementor-divider-separator">\n						</span>\n		</div>\n						</div>\n				</div>\n					</div>\n		</div>\n					</div>\n		</section>\n				<section class="elementor-section elementor-top-section elementor-element elementor-element-142854d elementor-section-boxed elementor-section-height-default elementor-section-height-default" data-id="142854d" data-element_type="section">\n						<div class="elementor-container elementor-column-gap-default">\n					<div class="elementor-column elementor-col-50 elementor-top-column elementor-element elementor-element-5c8b47a" data-id="5c8b47a" data-element_type="column">\n			<div class="elementor-widget-wrap elementor-element-populated">\n						<div class="elementor-element elementor-element-152974b elementor-widget elementor-widget-image" data-id="152974b" data-element_type="widget" data-widget_type="image.default">\n				<div class="elementor-widget-container">\n															<img loading="lazy" decoding="async" width="245" height="300" src="https://espacioepilepsia.org/wp-content/uploads/2023/05/4-autora-245x300.webp" class="attachment-medium size-medium wp-image-738" alt="" srcset="https://espacioepilepsia.org/wp-content/uploads/2023/05/4-autora-245x300.webp 245w, https://espacioepilepsia.org/wp-content/uploads/2023/05/4-autora-600x733.webp 600w, https://espacioepilepsia.org/wp-content/uploads/2023/05/4-autora.webp 720w" sizes="(max-width: 245px) 100vw, 245px" />															</div>\n				</div>\n					</div>\n		</div>\n				<div class="elementor-column elementor-col-50 elementor-top-column elementor-element elementor-element-7cd6246" data-id="7cd6246" data-element_type="column">\n			<div class="elementor-widget-wrap elementor-element-populated">\n						<div class="elementor-element elementor-element-0ebddcc elementor-widget elementor-widget-heading" data-id="0ebddcc" data-element_type="widget" data-widget_type="heading.default">\n				<div class="elementor-widget-container">\n					<h4 class="elementor-heading-title elementor-size-default">* María Julia Caterina</h4>				</div>\n				</div>\n				<div class="elementor-element elementor-element-9e4295d elementor-widget elementor-widget-text-editor" data-id="9e4295d" data-element_type="widget" data-widget_type="text-editor.default">\n				<div class="elementor-widget-container">\n									<p id="viewer-1c6o8" class="mm8Nw _1j-51 WkT0MK _1FoOD _3M0Fe T3Ond1 WkT0MK public-DraftStyleDefault-block-depth0 fixed-tab-size public-DraftStyleDefault-text-ltr"><span class="_2PHJq public-DraftStyleDefault-ltr">Licenciada en Trabajo Social, UNR. </span><span class="_2PHJq public-DraftStyleDefault-ltr">Reside en Rosario, pcia. de Santa Fe. </span><span class="_2PHJq public-DraftStyleDefault-ltr">Actualmente trabaja en el Ministerio de Desarrollo Social de la provincia Santa Fe. </span></p><p id="viewer-aquo6" class="mm8Nw _1j-51 WkT0MK _1FoOD _3M0Fe T3Ond1 WkT0MK public-DraftStyleDefault-block-depth0 fixed-tab-size public-DraftStyleDefault-text-ltr"><span class="_2PHJq public-DraftStyleDefault-ltr">mjuliacaterina@gmail.com</span></p>								</div>\n				</div>\n					</div>\n		</div>\n					</div>\n		</section>\n				</div>\n		', 'A continuación brindamos una serie de preguntas y respuestas sobre el Certificado Único de discapacidad que aplican a Argentina. ¿Que es el Certificado Único de Discapacidad (CUD)? El CUD es un documento que certifica la discapacidad de la persona y le permite acceder a derechos y prestaciones que brinda el Estado. Es un documento público [&hellip;]\n', 'blog', '2023-05-06T19:07:21', true, 'https://espacioepilepsia.org/wp-content/uploads/2023/05/1-blog.png');
